"""Tests for the pipeline console service."""from __future__ import annotationsimport tkinter as tkfrom src.core.logger import SYSTEM_LOGGERfrom src.gui.utils import ProjectPipelineConsoleclass _FakeText:    def __init__(self) -> None:        self._value = ""        self.state = tk.DISABLED    def winfo_exists(self) -> bool:        return True    def config(self, **kwargs: object) -> None:        if "state" in kwargs:            self.state = kwargs["state"]    def insert(self, _index: object, text: str) -> None:        self._value += text    def delete(self, start: str, end: str) -> None:        if start == "1.0" and end == tk.END:            self._value = ""            return        if start == "1.0" and end.endswith(".0"):            keep_from_line = max(1, int(end.split(".")[0]))            lines = self._value.splitlines()            self._value = "\n".join(lines[keep_from_line - 1 :])            if self._value:                self._value += "\n"    def see(self, _index: object) -> None:        return    def index(self, _index: object) -> str:        lines = self._value.splitlines()        line_count = len(lines) if lines else 1        return f"{line_count}.0"    def text(self) -> str:        return self._valuedef test_console_publish_clear_and_callback_order() -> None:    text = _FakeText()    console = ProjectPipelineConsole(text, drain_batch_size=10)    called: list[str] = []    console.publish("one")    console.publish("two")    console.clear()    console.publish("three")    console.call_in_ui(lambda: called.append("done"))    console.drain()    assert text.text() == "three\n"    assert called == ["done"]def test_console_trims_old_lines() -> None:    text = _FakeText()    console = ProjectPipelineConsole(text, max_lines=2, drain_batch_size=10)    console.publish("line1")    console.publish("line2")    console.publish("line3")    console.drain()    assert text.text() == "line2\nline3\n"def test_console_can_attach_and_detach_system_logger() -> None:    text = _FakeText()    console = ProjectPipelineConsole(text, drain_batch_size=10)    console.attach_system_logger()    try:        SYSTEM_LOGGER.info("system message")        console.drain()    finally:        console.detach_system_logger()    assert "system message" in text.text()